const COMP_FILTERS = { empleado: '', concepto: '', desde: '', hasta: '' };

window.rhCompSetFilter = function (k, v) { COMP_FILTERS[k] = v; rhRenderCompensaciones(); };
window.rhCompClearFilters = function () {
  COMP_FILTERS.empleado = ''; COMP_FILTERS.concepto = ''; COMP_FILTERS.desde = ''; COMP_FILTERS.hasta = '';
  rhRenderCompensaciones();
};

function compPeriodSpan(record) {
  const fp = record.Fecha_pago;
  if (!fp) return [null, null];
  const d = new Date(fp); if (isNaN(d)) return [null, null];
  const type = String(record.Periodo || '').split(':')[0].trim();
  if (type === 'Semanal') { const end = new Date(d); end.setDate(d.getDate() + 6); return [d, end]; }
  if (type === 'Quincenal') {
    if (d.getDate() <= 15) return [new Date(d.getFullYear(), d.getMonth(), 1), new Date(d.getFullYear(), d.getMonth(), 15)];
    return [new Date(d.getFullYear(), d.getMonth(), 16), new Date(d.getFullYear(), d.getMonth()+1, 0)];
  }
  if (type === 'Mensual') return [new Date(d.getFullYear(), d.getMonth(), 1), new Date(d.getFullYear(), d.getMonth()+1, 0)];
  return [d, d];
}

function rhRenderCompensaciones() {
  const view = document.getElementById('rh-view');
  const all = RH_STATE.compensaciones || [];
  const f = COMP_FILTERS;
  const fDesde = f.desde ? new Date(f.desde) : null;
  const fHasta = f.hasta ? new Date(f.hasta) : null;
  const rows = all.filter(r => {
    if (f.empleado && String(r.Empleado_ID) !== String(f.empleado)) return false;
    if (f.concepto && String(r.Concepto) !== f.concepto) return false;
    if (fDesde || fHasta) {
      const [s, e] = compPeriodSpan(r);
      if (!s || !e) return false;
      // overlap test: s <= fHasta && e >= fDesde
      if (fHasta && s > fHasta) return false;
      if (fDesde && e < fDesde) return false;
    }
    return true;
  });
  const empOpts = (RH_STATE.empleados || []).map(e => {
    const n = [e.Nombre, e.Apellido_paterno, e.Apellido_materno].filter(Boolean).join(' ') || e.Nombre || '';
    return `<option value="${esc(e.ID)}" ${String(e.ID) === String(f.empleado) ? 'selected':''}>${esc(n)}</option>`;
  }).join('');
  const conceptos = Array.from(new Set(all.map(r => r.Concepto).filter(Boolean))).sort();
  view.innerHTML = `
    <div class="rh-toolbar">
      <div>
        <div class="rh-toolbar-title">💵 Pago de Nómina</div>
        <div class="rh-toolbar-count">${rows.length} de ${all.length} registro(s)</div>
      </div>
      <button type="button" class="rh-btn-add" onclick="rhOpenNominaForm()">＋ Nueva operación</button>
    </div>
    <div class="comp-filters">
      <div class="rh-field"><label>Empleado</label>
        <select onchange="rhCompSetFilter('empleado', this.value)">
          <option value="">— Todos —</option>${empOpts}
        </select>
      </div>
      <div class="rh-field"><label>Concepto</label>
        <select onchange="rhCompSetFilter('concepto', this.value)">
          <option value="">— Todos —</option>
          ${conceptos.map(c => `<option value="${esc(c)}" ${c === f.concepto ? 'selected':''}>${esc(c)}</option>`).join('')}
        </select>
      </div>
      <div class="rh-field"><label>Desde</label>
        <input type="date" value="${esc(f.desde)}" onchange="rhCompSetFilter('desde', this.value)">
      </div>
      <div class="rh-field"><label>Hasta</label>
        <input type="date" value="${esc(f.hasta)}" onchange="rhCompSetFilter('hasta', this.value)">
      </div>
      <button type="button" class="comp-filter-clear" onclick="rhCompClearFilters()">Limpiar filtros</button>
    </div>
    ${rows.length === 0
      ? `<div class="rh-empty">${all.length === 0 ? 'Sin compensaciones registradas.' : 'Ningún registro coincide con los filtros.'}</div>`
      : `<div style="overflow-x:auto"><table class="rh-table">
          <thead><tr>
            <th style="width:28px"></th>
            <th>Empleado</th><th>Concepto</th><th>Periodo</th>
            <th style="text-align:right">Monto</th><th>Método de pago</th><th>Fecha de pago</th><th>Comentarios</th>
          </tr></thead>
          <tbody>${rows.map(r => `
            <tr onclick="rhOpenForm('compensacion','${esc(r.ID)}')">
              <td onclick="event.stopPropagation()"><button type="button" class="nom-conc-del" onclick="rhDeleteCompensacion('${esc(r.ID)}', event)" title="Eliminar">✕</button></td>
              <td><strong>${esc(rhEmpleadoNombre(r.Empleado_ID) || r.Empleado_Nombre || '—')}</strong></td>
              <td>${r.Concepto ? `<span class="rh-chip ${nomConceptoClass(r.Concepto)}">${esc(r.Concepto)}</span>` : '—'}</td>
              <td>${esc(r.Periodo || '—')}</td>
              <td style="text-align:right;font-weight:800;color:#16a34a">${r.Monto ? rhFmtMoney(r.Monto) : '—'}</td>
              <td>${r.Metodo_pago ? `<span class="rh-chip ${nomMetodoClass(r.Metodo_pago)}">${esc(r.Metodo_pago)}</span>` : '—'}</td>
              <td>${esc(r.Fecha_pago || '—')}</td>
              <td>${esc(r.Comentarios || '—')}</td>
            </tr>`).join('')}</tbody>
        </table></div>`}`;
}

// ── Form (slide-in panel) ──
window.rhOpenForm = function (kind, id) {
  // Reset footer buttons al estado por defecto (por si el form de nómina los cambió)
  const _btnPri = document.querySelector('#rh-form-panel .inc-btn-pri');
  const _btnSec = document.querySelector('#rh-form-panel .inc-btn-sec');
  if (_btnPri) { _btnPri.innerHTML = '💾 Guardar'; _btnPri.onclick = () => rhSaveCurrentForm(); _btnPri.style.display = ''; _btnPri.style.flex = '1'; }
  if (_btnSec) { _btnSec.innerHTML = 'Cancelar'; _btnSec.onclick = () => rhCloseForm(); _btnSec.style.flex = ''; }
  document.getElementById('rh-form-panel')?.classList.remove('panel-fullwidth');
  const empleadoOpts = (RH_STATE.empleados || [])
    .map(e => `<option value="${esc(e.ID)}">${esc(e.Nombre)}${e.Puesto ? ' — ' + esc(e.Puesto) : ''}</option>`).join('');
  let editing = null;
  let title = '';
  let bodyHtml = '';
  if (kind === 'empleado') {
    editing = id ? (RH_STATE.empleados || []).find(r => String(r.ID) === String(id)) : null;
    title = editing ? '✏️ Editar empleado' : '＋ Nuevo empleado';
    const noEmp = editing?.ID || '(se asignará al guardar)';
    const antig = rhCalcAntiguedad(editing?.Fecha_ingreso, editing?.Fecha_retiro);
    const diasDef = String(editing?.Dias_trabajo || '').split(',').map(s => s.trim()).filter(Boolean);
    bodyHtml = `
      <div class="rh-section">
        <div class="rh-section-title">👤 Datos generales</div>
        <div class="rh-grid-2">
          ${rhFieldText('Nombre','Nombre(s)',editing?.Nombre)}
          ${rhFieldText('Apellido_paterno','Apellido paterno',editing?.Apellido_paterno)}
          ${rhFieldText('Apellido_materno','Apellido materno',editing?.Apellido_materno)}
          ${rhFieldDate('Fecha_nacimiento','Fecha de nacimiento',editing?.Fecha_nacimiento)}
          ${rhFieldText('CURP','CURP',editing?.CURP)}
          ${rhFieldText('Telefono','Teléfono',editing?.Telefono)}
          ${rhFieldText('Celular','Celular',editing?.Celular)}
          ${rhFieldText('Email','Email',editing?.Email)}
        </div>
        ${rhFieldText('Direccion','Dirección',editing?.Direccion)}
      </div>

      <div class="rh-section">
        <div class="rh-section-title">💼 Nómina</div>
        <div class="rh-grid-2">
          <div class="rh-field"><label>No. de empleado</label><input type="text" value="${esc(noEmp)}" readonly style="background:#f1f5f9;color:#64748b"></div>
          ${rhFieldText('Puesto','Cargo',editing?.Puesto)}
          ${rhFieldSelect('Estado','Estado',['Activo','Inactivo','Suspendido'], editing?.Estado || (String(editing?.Activo||'').toLowerCase() === 'inactivo' ? 'Inactivo' : 'Activo'))}
          ${rhFieldSelect('Tipo_contrato','Tipo de contrato',['Indeterminado','Determinado','Honorarios','Por obra','Eventual'],editing?.Tipo_contrato)}
          ${rhFieldDate('Fecha_ingreso','Fecha de ingreso',editing?.Fecha_ingreso)}
          ${rhFieldDate('Fecha_retiro','Fecha de retiro',editing?.Fecha_retiro)}
          <div class="rh-field"><label>Antigüedad</label><input type="text" id="rh-antiguedad" value="${esc(antig)}" readonly style="background:#f1f5f9;color:#0f172a;font-weight:600"></div>
          ${rhFieldSelect('Periodicidad_pago','Periodicidad de pago',['Por día','Semanal','Quincenal','Mensual'],editing?.Periodicidad_pago)}
          ${rhFieldNumber('Salario_mensual','Salario mensual ($)',editing?.Salario_mensual)}
        </div>
        <div class="rh-grid-2">
          ${rhFieldTime('Hora_entrada','Hora de entrada',editing?.Hora_entrada)}
          ${rhFieldTime('Hora_salida','Hora de salida',editing?.Hora_salida)}
        </div>
        ${rhFieldDays('Dias_trabajo','Días de la semana que trabaja', diasDef)}
      </div>

      <div class="rh-section">
        <div class="rh-section-title">🏥 IMSS y SAT</div>
        <div class="rh-grid-2">
          ${rhFieldText('NSS','No. de Seguridad Social (IMSS)',editing?.NSS)}
          ${rhFieldText('RFC','RFC',editing?.RFC)}
        </div>
      </div>

      <div class="rh-section">
        <div class="rh-section-title">🏦 Datos bancarios</div>
        <div class="rh-grid-2">
          ${rhFieldText('Banco','Banco',editing?.Banco)}
          ${rhFieldText('CLABE','CLABE / Cuenta',editing?.CLABE)}
          ${rhFieldSelect('Tipo_cuenta','Tipo de cuenta',['Nómina','Ahorro','Cheques','Débito'],editing?.Tipo_cuenta)}
          ${rhFieldText('Cuentahabiente','Cuentahabiente',editing?.Cuentahabiente)}
        </div>
      </div>

      <div class="rh-section">
        <div class="rh-section-title">🚨 Contacto de emergencia</div>
        <div class="rh-grid-2">
          ${rhFieldText('Contacto_emergencia','Nombre del contacto',editing?.Contacto_emergencia)}
          ${rhFieldText('Tel_emergencia','Teléfono',editing?.Tel_emergencia)}
        </div>
      </div>`;
  } else if (kind === 'asistencia') {
    editing = id ? (RH_STATE.asistencia || []).find(r => String(r.ID) === String(id)) : null;
    title = editing ? '✏️ Editar asistencia' : '＋ Registrar asistencia';
    bodyHtml = `
      ${rhFieldEmpleadoSelect(editing?.Empleado_ID, empleadoOpts)}
      <div class="rh-grid-2">
        ${rhFieldDate('Fecha','Fecha',editing?.Fecha || new Date().toISOString().slice(0,10))}
        ${rhFieldText('Entrada','Hora de entrada (ej. 08:00)',editing?.Entrada)}
        ${rhFieldText('Salida','Hora de salida (ej. 17:00)',editing?.Salida)}
        ${rhFieldNumber('Horas','Horas trabajadas',editing?.Horas)}
        ${rhFieldNumber('Horas_extra','Horas extra',editing?.Horas_extra)}
      </div>
      ${rhFieldTextarea('Observaciones','Observaciones',editing?.Observaciones)}`;
  } else if (kind === 'ausencia') {
    editing = id ? (RH_STATE.ausencias || []).find(r => String(r.ID) === String(id)) : null;
    title = editing ? '✏️ Editar ausencia' : '＋ Registrar ausencia';
    bodyHtml = `
      ${rhFieldEmpleadoSelect(editing?.Empleado_ID, empleadoOpts)}
      <div class="rh-grid-2">
        ${rhFieldSelect('Tipo','Tipo',['Vacaciones','Permiso con goce','Permiso sin goce','Incapacidad','Maternidad','Paternidad','Otro'],editing?.Tipo)}
        ${rhFieldSelect('Estatus','Estatus',['Solicitada','Aprobada','Rechazada'],editing?.Estatus || 'Solicitada')}
        ${rhFieldDate('Fecha_inicio','Fecha de inicio',editing?.Fecha_inicio)}
        ${rhFieldDate('Fecha_fin','Fecha de fin',editing?.Fecha_fin)}
        ${rhFieldNumber('Dias','Días',editing?.Dias)}
      </div>
      ${rhFieldTextarea('Comentarios','Comentarios',editing?.Comentarios)}`;
  } else if (kind === 'compensacion') {
    editing = id ? (RH_STATE.compensaciones || []).find(r => String(r.ID) === String(id)) : null;
    title = editing ? '✏️ Editar compensación' : '＋ Registrar compensación';
    bodyHtml = `
      ${rhFieldEmpleadoSelect(editing?.Empleado_ID, empleadoOpts)}
      <div class="rh-grid-2">
        ${rhFieldSelect('Concepto','Concepto',['Salario','Compensación','Prima vacacional','Día festivo','Préstamo','Ahorro','Otro'],editing?.Concepto)}
        ${rhFieldText('Periodo','Periodo (ej. Diciembre 2026, S2-2026)',editing?.Periodo)}
        ${rhFieldNumber('Monto','Monto ($)',editing?.Monto)}
        ${rhFieldSelect('Metodo_pago','Método de pago',['Transferencia bancaria','Efectivo'],editing?.Metodo_pago || 'Transferencia bancaria')}
        ${rhFieldDate('Fecha_pago','Fecha de pago',editing?.Fecha_pago)}
      </div>
      ${rhFieldTextarea('Comentarios','Comentarios',editing?.Comentarios)}`;
  }
  RH_STATE.formContext = { kind, editing };
  document.getElementById('rh-form-title').textContent = title;
  document.getElementById('rh-form-body').innerHTML = bodyHtml;
  const panel = document.getElementById('rh-form-panel');
  const back  = document.getElementById('rh-form-backdrop');
  back.classList.remove('hidden');
  back.offsetHeight;
  back.classList.add('visible');
  panel.classList.remove('hidden');
  panel.classList.add('open');
  if (kind === 'empleado') {
    setTimeout(() => {
      const fi = document.querySelector('#rh-form-body [data-rh-field="Fecha_ingreso"]');
      const fr = document.querySelector('#rh-form-body [data-rh-field="Fecha_retiro"]');
      const out = document.getElementById('rh-antiguedad');
      const refresh = () => { if (out) out.value = rhCalcAntiguedad(fi?.value, fr?.value); };
      if (fi) fi.addEventListener('change', refresh);
      if (fr) fr.addEventListener('change', refresh);
    }, 50);
  }
  // Dirty-state para edición de compensaciones: solo mostrar "Guardar cambios" si cambió algo
  if (kind === 'compensacion' && editing) {
    setTimeout(() => {
      const body = document.getElementById('rh-form-body');
      const btnPri = document.querySelector('#rh-form-panel .inc-btn-pri');
      const btnSec = document.querySelector('#rh-form-panel .inc-btn-sec');
      const snapshot = (() => {
        const o = {};
        body.querySelectorAll('[data-rh-field]').forEach(el => { o[el.getAttribute('data-rh-field')] = el.value || ''; });
        return o;
      })();
      if (btnPri) { btnPri.style.display = 'none'; btnPri.innerHTML = '💾 Guardar cambios y Salir'; btnPri.onclick = () => rhSaveCurrentForm(); }
      if (btnSec) { btnSec.innerHTML = '🚪 Salir'; btnSec.onclick = () => rhCloseForm(); btnSec.style.flex = '1'; }
      const checkDirty = () => {
        let dirty = false;
        body.querySelectorAll('[data-rh-field]').forEach(el => {
          const k = el.getAttribute('data-rh-field');
          if ((el.value || '') !== (snapshot[k] || '')) dirty = true;
        });
        if (btnPri) btnPri.style.display = dirty ? '' : 'none';
        if (btnSec) btnSec.style.flex = dirty ? '' : '1';
      };
      body.addEventListener('input', checkDirty);
      body.addEventListener('change', checkDirty);
    }, 50);
  }
};

window.rhCloseForm = function () {
  const panel = document.getElementById('rh-form-panel');
  const back  = document.getElementById('rh-form-backdrop');
  panel.classList.remove('open');
  back.classList.remove('visible');
  setTimeout(() => { panel.classList.add('hidden'); back.classList.add('hidden'); }, 280);
};

window.rhSaveCurrentForm = async function () {
  const ctx = RH_STATE.formContext;
  if (!ctx) return;
  const inputs = document.querySelectorAll('#rh-form-body [data-rh-field]');
  const payload = {};
  inputs.forEach(el => { payload[el.getAttribute('data-rh-field')] = el.value || ''; });
  // Si es edición, conserva el ID
  if (ctx.editing && ctx.editing.ID) payload.ID = ctx.editing.ID;
  // Empacar Dias_trabajo desde checkboxes
  const diasBoxes = document.querySelectorAll('#rh-form-body input[data-rh-day]:checked');
  if (diasBoxes.length || document.querySelector('#rh-form-body input[data-rh-day]')) {
    payload.Dias_trabajo = Array.from(diasBoxes).map(b => b.getAttribute('data-rh-day')).join(',');
  }
  // Sincronizar Estado <-> Activo (backward compat)
  if (ctx.kind === 'empleado' && payload.Estado) {
    payload.Activo = (payload.Estado === 'Activo') ? 'Activo' : 'Inactivo';
  }
  // Validación mínima
  if (ctx.kind === 'empleado') {
    if (!payload.Nombre) { alert('El nombre es obligatorio.'); return; }
  } else if (!payload.Empleado_ID) {
    alert('Selecciona un empleado.'); return;
  }
  // Empleado_Nombre para mostrar en tablas (denormalizado)
  if (payload.Empleado_ID) {
    payload.Empleado_Nombre = rhEmpleadoNombre(payload.Empleado_ID);
  }
  const endpoint = {
    empleado: '/rh/empleados',
    asistencia: '/rh/asistencia',
    ausencia: '/rh/ausencias',
    compensacion: '/rh/compensaciones',
  }[ctx.kind];
  const btn = document.querySelector('#rh-form-panel .inc-btn-pri');
  const orig = btn ? btn.innerHTML : '';
  if (btn) { btn.disabled = true; btn.innerHTML = '⏳ Guardando…'; }
  try {
    const res = await fetch(`${BACKEND}${endpoint}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ payload }),
    });
    const out = await res.json();
    if (!out.ok) throw new Error(out.error || 'Error');
    rhCloseForm();
    // Recargar el catálogo si era empleado, luego re-render
    if (ctx.kind === 'empleado') await rhLoadEmpleados();
    if (ctx.kind === 'asistencia') await rhLoadAsistencia();
    if (ctx.kind === 'ausencia') await rhLoadAusencias();
    if (ctx.kind === 'compensacion') await rhLoadCompensaciones();
    rhSetTab(RH_STATE.tab);
  } catch (e) {
    alert('No se pudo guardar:\n' + (e.message || e));
  } finally {
    if (btn) { btn.disabled = false; btn.innerHTML = orig; }
  }
};

// ── Helpers de campos ──
function rhFieldText(name, label, val) {
  return `<div class="rh-field"><label>${esc(label)}</label><input type="text" data-rh-field="${esc(name)}" value="${esc(val || '')}"></div>`;
}
function rhFieldDate(name, label, val) {
  return `<div class="rh-field"><label>${esc(label)}</label><input type="date" data-rh-field="${esc(name)}" value="${esc(val || '')}"></div>`;
}
function rhFieldNumber(name, label, val) {
  return `<div class="rh-field"><label>${esc(label)}</label><input type="number" step="0.01" data-rh-field="${esc(name)}" value="${esc(val || '')}"></div>`;
}
function rhFieldTextarea(name, label, val) {
  return `<div class="rh-field"><label>${esc(label)}</label><textarea rows="3" data-rh-field="${esc(name)}">${esc(val || '')}</textarea></div>`;
}
function rhFieldSelect(name, label, opts, val) {
  return `<div class="rh-field"><label>${esc(label)}</label><select data-rh-field="${esc(name)}">
    <option value="">— Seleccionar —</option>
    ${opts.map(o => `<option value="${esc(o)}" ${o === val ? 'selected' : ''}>${esc(o)}</option>`).join('')}
  </select></div>`;
}
function rhFieldEmpleadoSelect(val, empleadoOpts) {
  return `<div class="rh-field"><label>Empleado</label><select data-rh-field="Empleado_ID">
    <option value="">— Seleccionar empleado —</option>${empleadoOpts.replace(/value="([^"]+)"/g, (m, v) => v === val ? `value="${v}" selected` : `value="${v}"`)}
  </select></div>`;
}
function rhFieldTime(name, label, val) {
  return `<div class="rh-field"><label>${esc(label)}</label><input type="time" data-rh-field="${esc(name)}" value="${esc(val || '')}"></div>`;
}
function rhFieldDays(name, label, selected) {
  const DIAS = [['L','Lun'],['M','Mar'],['Mi','Mié'],['J','Jue'],['V','Vie'],['S','Sáb'],['D','Dom']];
  const sel = new Set(selected || []);
  return `<div class="rh-field"><label>${esc(label)}</label>
    <div class="rh-days">${DIAS.map(([k, lbl]) => `
      <label class="rh-day ${sel.has(k) ? 'on' : ''}">
        <input type="checkbox" data-rh-day="${k}" ${sel.has(k) ? 'checked' : ''}
          onchange="this.parentElement.classList.toggle('on', this.checked)">
        <span>${lbl}</span>
      </label>`).join('')}</div>
  </div>`;
}
function rhCalcAntiguedad(ingreso, retiro) {
  if (!ingreso) return '—';
  const a = new Date(ingreso);
  if (isNaN(a)) return '—';
  const b = retiro ? new Date(retiro) : new Date();
  if (isNaN(b) || b < a) return '—';
  let years = b.getFullYear() - a.getFullYear();
  let months = b.getMonth() - a.getMonth();
  let days = b.getDate() - a.getDate();
  if (days < 0) {
    months--;
    const prev = new Date(b.getFullYear(), b.getMonth(), 0);
    days += prev.getDate();
  }
  if (months < 0) { months += 12; years--; }
  const parts = [];
  if (years) parts.push(years + ' año' + (years === 1 ? '' : 's'));
  if (months) parts.push(months + ' mes' + (months === 1 ? '' : 'es'));
  if (!years && !months) parts.push(days + ' día' + (days === 1 ? '' : 's'));
  return parts.join(', ') || '—';
}

// ═══════════════════════════════════════════════════════════════════════
// ║  PAGO DE NÓMINA — formulario multi-modo (Unitario / Grupal)           ║
// ═══════════════════════════════════════════════════════════════════════
const NOM_CONCEPTOS = ['Salario','Compensación','Prima vacacional','Día festivo','Préstamo','Ahorro','Otro'];
const NOM_METODOS   = ['Transferencia bancaria','Efectivo'];
const NOM_PERIODOS  = ['Pago único','Semanal','Quincenal','Mensual'];
const NOM_MONTHS_ABR  = ['ene','feb','mar','abr','may','jun','jul','ago','sep','oct','nov','dic'];
const NOM_MONTHS_FULL = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];

const NOM_STATE = {
  mode: 'unit',
  unitEmpleadoId: '',
  unitConceptos: [],
  grupalRows: [],
};

window.rhOpenNominaForm = function () {
  RH_STATE.formContext = { kind: 'nomina_multi', editing: null };
  document.getElementById('rh-form-title').textContent = '＋ Nueva operación';
  document.getElementById('rh-form-body').innerHTML = `
    <div class="nom-cejas">
      <button type="button" class="nom-ceja active" data-mode="unit" onclick="nomSetMode('unit')">📝 Registro unitario</button>
      <button type="button" class="nom-ceja" data-mode="grupal" onclick="nomSetMode('grupal')">👥 Registro grupal</button>
    </div>
    <div id="nom-pane"></div>`;
  NOM_STATE.mode = 'unit';
  NOM_STATE.unitEmpleadoId = '';
  NOM_STATE.unitConceptos = [nomEmptyConcepto()];
  NOM_STATE.grupalRows = (RH_STATE.empleados || []).map(e => ({
    empleadoId: e.ID,
    nombre: [e.Nombre, e.Apellido_paterno, e.Apellido_materno].filter(Boolean).join(' ') || e.Nombre || '—',
    concepto: 'Salario',
    periodo: 'Semanal',
    fecha: nomDefaultPeriodValue('Semanal'),
    monto: 2205.28,
    metodoPago: 'Transferencia bancaria',
    fechaPago: nomComputeFechaPago('Semanal', nomDefaultPeriodValue('Semanal')),
    notas: '',
  }));
  nomRenderPane();
  const panel = document.getElementById('rh-form-panel');
  const back  = document.getElementById('rh-form-backdrop');
  back.classList.remove('hidden'); back.offsetHeight; back.classList.add('visible');
  panel.classList.remove('hidden'); panel.classList.add('open');
  panel.classList.add('panel-fullwidth');
  // Footer: Guardar y Salir + Limpiar
  const btnPri = document.querySelector('#rh-form-panel .inc-btn-pri');
  const btnSec = document.querySelector('#rh-form-panel .inc-btn-sec');
  if (btnPri) { btnPri.innerHTML = '💾 Guardar y Salir'; btnPri.onclick = () => nomSave(); }
  if (btnSec) { btnSec.innerHTML = '🗑 Limpiar'; btnSec.onclick = () => nomClear(); }
};

function nomEmptyConcepto() {
  const fecha = nomDefaultPeriodValue('Semanal');
  return { concepto: 'Salario', periodo: 'Semanal', fecha, fechaPago: nomComputeFechaPago('Semanal', fecha), monto: '', metodoPago: 'Transferencia bancaria', notas: '' };
}

window.nomSetMode = function (m) {
  NOM_STATE.mode = m;
  document.querySelectorAll('.nom-ceja').forEach(b => b.classList.toggle('active', b.getAttribute('data-mode') === m));
  nomRenderPane();
};

function nomRenderPane() {
  const pane = document.getElementById('nom-pane');
  if (!pane) return;
  pane.innerHTML = NOM_STATE.mode === 'unit' ? nomRenderUnit() : nomRenderGrupal();
}

function nomRenderUnit() {
  const empOpts = (RH_STATE.empleados || []).map(e => {
    const n = [e.Nombre, e.Apellido_paterno, e.Apellido_materno].filter(Boolean).join(' ') || e.Nombre || '';
    return `<option value="${esc(e.ID)}" ${String(e.ID) === String(NOM_STATE.unitEmpleadoId) ? 'selected':''}>${esc(n)}${e.Puesto ? ' — ' + esc(e.Puesto) : ''}</option>`;
  }).join('');
  return `
    <div class="rh-field"><label>Empleado</label>
      <select onchange="NOM_STATE.unitEmpleadoId=this.value">
        <option value="">— Seleccionar empleado —</option>${empOpts}
      </select>
    </div>
    <div id="nom-conceptos-list">
      ${NOM_STATE.unitConceptos.map((c, i) => nomRenderConceptoBox(c, i)).join('')}
    </div>
    <button type="button" class="rh-btn-add" style="margin-top:8px" onclick="nomAddConcepto()">＋ Agregar concepto</button>
  `;
}

function nomRenderConceptoBox(c, i) {
  return `
  <div class="nom-conc-box" data-idx="${i}">
    <div class="nom-conc-head">
      <span>Concepto ${i+1}</span>
      ${i > 0 ? `<button type="button" class="nom-conc-del" onclick="nomDelConcepto(${i})" title="Eliminar">✕</button>` : ''}
    </div>
    <div class="rh-grid-2">
      <div class="rh-field"><label>Concepto de pago</label>
        <select onchange="NOM_STATE.unitConceptos[${i}].concepto=this.value">
          ${NOM_CONCEPTOS.map(o => `<option value="${o}" ${o===c.concepto?'selected':''}>${o}</option>`).join('')}
        </select>
      </div>
      <div class="rh-field"><label>Periodicidad</label>
        <select onchange="nomChangeUnitPeriodo(${i}, this.value)">
          ${NOM_PERIODOS.map(o => `<option value="${o}" ${o===c.periodo?'selected':''}>${o}</option>`).join('')}
        </select>
      </div>
    </div>
    <div class="rh-grid-2">
      <div class="rh-field"><label>Periodo laborado</label>
        ${nomPeriodInput(c.periodo, c.fecha, `nomSetUnitFecha(${i}, this.value)`)}
      </div>
      <div class="rh-field"><label>Fecha de pago</label>
        <input type="date" id="nom-fp-unit-${i}" value="${esc(c.fechaPago||'')}" onchange="NOM_STATE.unitConceptos[${i}].fechaPago=this.value">
      </div>
    </div>
    <div class="rh-grid-2">
      <div class="rh-field"><label>$ Monto</label>
        <input type="text" value="${c.monto !== '' ? nomFmtCurrency(c.monto) : ''}"
          oninput="NOM_STATE.unitConceptos[${i}].monto=nomParseMoney(this.value)"
          onblur="this.value = NOM_STATE.unitConceptos[${i}].monto ? nomFmtCurrency(NOM_STATE.unitConceptos[${i}].monto) : ''">
      </div>
      <div class="rh-field"><label>Método de pago</label>
        <select onchange="NOM_STATE.unitConceptos[${i}].metodoPago=this.value">
          ${NOM_METODOS.map(o => `<option value="${o}" ${o===(c.metodoPago||'Transferencia bancaria')?'selected':''}>${o}</option>`).join('')}
        </select>
      </div>
    </div>
    <div class="rh-field"><label>Notas</label>
      <textarea rows="2" oninput="NOM_STATE.unitConceptos[${i}].notas=this.value">${esc(c.notas||'')}</textarea>
    </div>
  </div>`;
}

window.nomAddConcepto = function () { NOM_STATE.unitConceptos.push(nomEmptyConcepto()); nomRenderPane(); };
